namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the app!"),
            CreateNotification("Your profile was created."),
            CreateNotification("You have a new follower."),
        });
    }

    /// <summary>Returns all notifications currently available.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns only notifications newer than the given ID.</summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally by a hosted service.
    /// </summary>
    public void GenerateRandom()
    {
        string[] templates =
        [
            "New comment on your post",
            "Someone liked your photo",
            "System maintenance scheduled",
            "Your export is ready",
            "New login from a new device",
            "Weekly digest available",
        ];

        lock (_lock)
        {
            var msg = templates[Random.Shared.Next(templates.Length)];
            _notifications.Add(CreateNotification(msg));
        }
    }

    private Notification CreateNotification(string message) =>
        new(_nextId++, message, DateTime.UtcNow);
}

namespace NotificationsApp.Services;

/// <summary>
/// Background hosted service that periodically generates fake notifications
/// so the polling page has new data to discover.
/// </summary>
public class NotificationGeneratorService(NotificationService notifications) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            notifications.GenerateRandom();
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationSvc

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Id))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationsApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    // Runs during both prerender AND interactive init.
    // On prerender it seeds the HTML; on interactive init the same data is
    // still in _notifications so we skip re-fetching.
    protected override void OnInitialized()
    {
        if (_notifications.Count == 0)
        {
            _notifications = NotificationSvc.GetAll();
            _lastSeenId = _notifications.Count > 0
                ? _notifications.Max(n => n.Id)
                : 0;
        }
    }

    // Called only once the circuit is live (never during prerender).
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newer = NotificationSvc.GetSince(_lastSeenId);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _lastSeenId = newer.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

