@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationSvc

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Id))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationsApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    // Runs during both prerender AND interactive init.
    // On prerender it seeds the HTML; on interactive init the same data is
    // still in _notifications so we skip re-fetching.
    protected override void OnInitialized()
    {
        if (_notifications.Count == 0)
        {
            _notifications = NotificationSvc.GetAll();
            _lastSeenId = _notifications.Count > 0
                ? _notifications.Max(n => n.Id)
                : 0;
        }
    }

    // Called only once the circuit is live (never during prerender).
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newer = NotificationSvc.GetSince(_lastSeenId);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _lastSeenId = newer.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

